import{_ as t,c as a,o,a1 as n}from"./chunks/framework.DDNAyvCW.js";const i="/assets/keys.DnthdFRe.png",u=JSON.parse('{"title":"Key Management","description":"","frontmatter":{},"headers":[],"relativePath":"docs/manage/keys/index.md","filePath":"docs/manage/keys/index.md"}'),r={name:"docs/manage/keys/index.md"};function s(d,e,l,h,c,y){return o(),a("div",null,e[0]||(e[0]=[n('<h1 id="key-management" tabindex="-1">Key Management <a class="header-anchor" href="#key-management" aria-label="Permalink to &quot;Key Management&quot;">​</a></h1><p>Manage your SSH keys in one place for secure, password-free authentication to your hosts.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before adding a key, make sure you have:</p><ul><li><strong>Chaterm installed</strong> and running on your machine.</li><li><strong>An SSH key pair</strong> (public key and private key). If you do not have one yet, generate a pair with <code>ssh-keygen</code> or a similar tool.</li></ul><h2 id="when-do-you-need-a-key" tabindex="-1">When Do You Need a Key? <a class="header-anchor" href="#when-do-you-need-a-key" aria-label="Permalink to &quot;When Do You Need a Key?&quot;">​</a></h2><p>When you <a href="/docs/hosts/add-personal">add a host</a>, Chaterm offers two authentication methods:</p><table tabindex="0"><thead><tr><th>Method</th><th>When to Use</th></tr></thead><tbody><tr><td><strong>Password</strong></td><td>You know the server password and do not have an SSH key deployed on the server.</td></tr><tr><td><strong>Key</strong></td><td>You have deployed a public key on the server and want to authenticate without typing a password every time.</td></tr></tbody></table><p>If you choose key authentication, you must first add your private key here so Chaterm can use it during connection.</p><h2 id="adding-a-key" tabindex="-1">Adding a Key <a class="header-anchor" href="#adding-a-key" aria-label="Permalink to &quot;Adding a Key&quot;">​</a></h2><p><img src="'+i+`" alt=""></p><ol><li>Click <strong>Key Management</strong> in the left sidebar.</li><li>Click the <strong>New Key</strong> button. The add-key dialog opens.</li><li>Fill in the fields described below.</li><li>Click <strong>Create</strong> to save the key.</li></ol><h3 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>Key Name</strong></td><td>A friendly label for this key (e.g., <code>Production Server Key</code>).</td><td>Yes</td></tr><tr><td><strong>Private Key</strong></td><td>The private key content. You can paste it manually or drag a private key file into the import area.</td><td>Yes</td></tr><tr><td><strong>Public Key</strong></td><td>The matching public key content. Optional but recommended for reference.</td><td>No</td></tr><tr><td><strong>Private Key Password</strong></td><td>The passphrase that protects the private key, if one was set during key generation.</td><td>No</td></tr></tbody></table><h3 id="import-methods" tabindex="-1">Import Methods <a class="header-anchor" href="#import-methods" aria-label="Permalink to &quot;Import Methods&quot;">​</a></h3><p><strong>File import</strong></p><ul><li>Drag your private key file into the area labeled &quot;Drag private key file here to import.&quot;</li><li>Chaterm automatically detects the key format. Supported formats include <code>.pem</code>, <code>.key</code>, <code>.rsa</code>, and <code>id_rsa</code>.</li></ul><p><strong>Manual input</strong></p><ul><li>Paste the full private key content into the <strong>Private Key</strong> field. The content should look similar to:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-----BEGIN RSA PRIVATE KEY-----</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>-----END RSA PRIVATE KEY-----</span></span></code></pre></div></li></ul><h2 id="using-a-key-with-a-host" tabindex="-1">Using a Key with a Host <a class="header-anchor" href="#using-a-key-with-a-host" aria-label="Permalink to &quot;Using a Key with a Host&quot;">​</a></h2><p>After adding a key, you can select it when creating or editing a host:</p><ol><li>Go to <strong>Host Management</strong> and click <strong>Add Host</strong> (or edit an existing host).</li><li>Set the <strong>Authentication Method</strong> to <strong>Key</strong>.</li><li>Choose the key you added from the dropdown list.</li><li>Save the host.</li></ol><p>When you connect to that host, Chaterm automatically uses the selected key for authentication -- no password prompt required.</p><p>For full details on adding a host, see <a href="/docs/hosts/add-personal">Add a Personal Host</a>.</p><h2 id="editing-a-key" tabindex="-1">Editing a Key <a class="header-anchor" href="#editing-a-key" aria-label="Permalink to &quot;Editing a Key&quot;">​</a></h2><ol><li>In the key list, locate the key you want to change.</li><li>Click the <strong>Edit</strong> button.</li><li>Update the key name, private key content, public key, or passphrase as needed.</li><li>Click <strong>Save</strong>. Changes take effect immediately.</li></ol><h2 id="deleting-a-key" tabindex="-1">Deleting a Key <a class="header-anchor" href="#deleting-a-key" aria-label="Permalink to &quot;Deleting a Key&quot;">​</a></h2><ol><li>In the key list, locate the key you want to remove.</li><li>Click the <strong>Delete</strong> button.</li><li>Confirm the deletion in the dialog that appears.</li></ol><div class="warning custom-block"><p class="custom-block-title">Before You Delete</p><p>Deleting a key is <strong>irreversible</strong>. Before you proceed:</p><ul><li>Verify that <strong>no hosts are currently using this key</strong> for authentication. Hosts that rely on a deleted key will fail to connect.</li><li>Back up the private key content externally if you may need it again.</li></ul></div>`,29)]))}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
